function outer() {
  const message = 'Hello from closure!';
  function inner() {
    console.log(message);
  }
  return inner;
}

const myClosure = outer();
myClosure(); // Output: Hello from closure!

function createCounter() {
  let count = 0;
  return {
    increment() {
      count++;
      console.log(count);
    },
    decrement() {
      count--;
      console.log(count);
    }
  };
}

const counter = createCounter();
counter.increment(); // 1
counter.increment(); // 2
counter.decrement(); // 1

function fetchData() {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      reject(new Error('Failed to fetch data'));
    }, 100);
  });
}

function processData() {
  fetchData()
    .then(data => console.log(data))
    .catch(error => console.error(error));
}

processData();

async function fetchData() {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      reject(new Error('Failed to fetch data'));
    }, 100);
  });
}

async function processData() {
  try {
    const data = await fetchData();
    console.log(data);
  } catch (error) {
    console.error(error);
  }
}

processData();

function betterFetchData() {
  const originalError = new Error('Call stack at fetch start');
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      const error = new Error('Failed to fetch data');
      // Combine the original stack and error stack
      error.stack += '\nCaused By: ' + originalError.stack;
      reject(error);
    }, 100);
  });
}

async function test() {
  try {
    await betterFetchData();
  } catch (err) {
    console.error(err);
  }
}

test();

